import base64
import io
import zipfile
from pathlib import Path

PROJECT_ZIP_BASE64 = ''''''

root = Path.cwd()
archive = base64.b64decode(PROJECT_ZIP_BASE64)
with zipfile.ZipFile(io.BytesIO(archive)) as zf:
    zf.extractall(root)
print('Career Autopilot project files were restored into:', root)
print('Next steps:')
print('1. cp .env.example .env')
print('2. nano .env and set TELEGRAM_BOT_TOKEN')
print('3. docker compose up -d --build')
